INSERT INTO foods (category_id, name, type, description, image_url, address, latitude, longitude, price_range, rating, tags, is_recommended, view_count) VALUES
(1, '八合里海记牛肉火锅', 'shop', '汕头最知名的牛肉火锅老字号，以新鲜现切牛肉闻名。脖仁、吊龙、匙仁、五花趾等部位应有尽有，汤底清甜，蘸沙茶酱食用风味最佳。', '/images/food/八合里海记牛肉火锅/20240501120102493.png', '汕头市金平区黄岗路坪西2座', 23.3650, 116.6820, '人均80-150元', 4.7, '["牛肉火锅","老字号","汕头必吃"]', TRUE, 12580),
(1, '杏花吴记牛肉火锅', 'shop', '汕头网红牛肉火锅店，环境好、服务佳，牛肉新鲜程度不输老店，深受年轻人喜爱。', '/images/food/杏花吴记牛肉火锅/100j11000000qdaskAF57.jpg', '汕头市龙湖区长平路88号', 23.3640, 116.7100, '人均100-200元', 4.5, '["牛肉火锅","网红店","环境好"]', TRUE, 9200),
(1, '福合埕牛肉丸', 'shop', '始于1960年的老字号，牛肉丸弹牙多汁，是潮汕牛肉丸的标杆。', '/images/food/福合埕牛肉丸/26987172adda99b5.jpg', '汕头市金平区福平路15号', 23.3600, 116.6780, '人均60-100元', 4.3, '["牛肉火锅","牛肉丸","老字号"]', FALSE, 7800),
(2, '老四粿条汤', 'shop', '汕头老市区知名粿条汤店，汤底用猪骨熬制数小时，粿条滑嫩，配以猪肉、猪肝、鱼丸，撒上蒜头酥和芹菜末。', '/images/food/老四粿条汤/微信图片_20260713194647_63_206.jpg', '汕头市金平区民族路68号', 23.3580, 116.6750, '人均15-30元', 4.4, '["粿条","早餐","老市区"]', TRUE, 8320),
(2, '老妈宫粽球', 'dish', '潮汕特色粽子——"粽球"，咸甜双拼，一半是咸香糯米配五花肉、香菇、咸蛋黄，一半是甜糯米配豆沙、白果。', '/images/food/老妈宫粽球/c9bfc8a2e9be60b5.jpg', '', NULL, NULL, NULL, 4.2, '["粽球","小吃","特色"]', TRUE, 5400),
(3, '富苑饮食', 'shop', '汕头知名打冷/生腌专门店，生腌虾、生腌蟹、生腌血蚶被誉为"潮汕毒药"——吃了会上瘾。', '/images/food/富苑饮食/OIP-C (1).webp', '汕头市龙湖区嵩山路29号', 23.3720, 116.7200, '人均150-300元', 4.6, '["生腌","海鲜","夜宵"]', TRUE, 7500),
(3, '建业酒家', 'shop', '老牌潮菜馆，以卤鹅、冻蟹、响螺等经典潮菜闻名，是品尝正宗潮州菜的好去处。', '/images/food/建业酒家/微信图片_20260713200250_69_206.jpg', '汕头市金平区凤凰山路12号', 23.3680, 116.6950, '人均200-500元', 4.3, '["潮菜","海鲜","宴请"]', FALSE, 5100),
(4, '广场老牌豆花', 'shop', '汕头人民广场旁的豆花老店，豆花口感绵密豆香浓郁，撒上红糖姜汁，是潮汕独有的甜豆花吃法。', '/images/food/广场老牌豆花/微信图片_20260713195630_67_206.jpg', '汕头市金平区公园路44号', 23.3560, 116.6730, '人均10-20元', 4.5, '["豆花","甜品","老字号"]', TRUE, 6800),
(4, '飘香小食店', 'shop', '汕头老市区知名小吃店，汇集了蚝烙、鲎粿、无米粿、水晶球等多种潮汕传统小吃。', '/images/food/飘香小食店/微信图片_20260713200447_71_206.jpg', '汕头市金平区国平路39号', 23.3600, 116.6760, '人均15-40元', 4.1, '["小吃","老市区","一站式"]', FALSE, 4500),
(5, '甘草水果', 'dish', '潮汕街头随处可见的消暑甜品，新鲜水果切块用甘草汁腌制，酸甜回甘，开胃解腻。', '/images/food/甘草水果/OIP-C (2).webp', '', NULL, NULL, NULL, 4.0, '["甜品","消暑","街头"]', FALSE, 3200),
(6, '长平路夜粥', 'shop', '汕头长平路夜粥一条街，深夜依然灯火通明。白粥配杂咸（各种小菜），是潮汕人最爱的夜宵方式。', '/images/food/长平路夜粥/0b3f0dbd2a262cb5.jpg', '汕头市金平区长平路', 23.3650, 116.6880, NULL, 4.0, '["夜宵","夜粥","深夜食堂"]', FALSE, 4100),
(1, '潮记牛肉火锅', 'shop', '潮州本地人推荐，牛肉从屠宰到上桌不超过2小时，保证极致新鲜。', '/images/food/潮记牛肉火锅/a275-a87e0c52968d2dbc19a04d9625052813.png', '潮州市湘桥区环城西路102号', 23.6650, 116.6350, '人均70-120元', 4.2, '["牛肉火锅","新鲜","潮州"]', FALSE, 3600),
(4, '西天巷蚝烙', 'dish', '潮汕经典小吃，新鲜蚝仔加番薯粉浆煎至金黄酥脆，蘸鱼露食用。外酥内嫩，蚝仔鲜美多汁。', '/images/food/西天巷蚝烙/R-C (1).jpg', '', NULL, NULL, NULL, 4.4, '["蚝烙","小吃","海鲜"]', FALSE, 5500),
(3, '达濠鱼丸', 'dish', '汕头达濠特产，手工打制的鱼丸弹牙爽口，可煮汤、可油炸、可做粿条配料。', '/images/food/达濠鱼丸/OIP-C (3).webp', '', NULL, NULL, NULL, 4.1, '["鱼丸","特产","小吃"]', FALSE, 2800),
(7, '澄海卤鹅', 'dish', '潮汕卤水代表作，选用澄海狮头鹅，以八角、桂皮、南姜等多种香料卤制，肉质鲜嫩，卤香入味。', '/images/food/澄海卤鹅/34519393_150628885107_2.jpg', '', NULL, NULL, NULL, 4.3, '["卤味","狮头鹅","伴手礼"]', TRUE, 4700),
(7, '春梅里鹅肉店', 'shop', '汕头老市区最富盛名的卤鹅专门店，始创于二十世纪四十年代，至今已传承三代。选用澄海狮头鹅，秘制卤水配方历经数十年精心调配，卤出的鹅肉皮脆肉嫩、卤香浓郁，鹅肝粉嫩滑口入口即化。每天限量供应，上午十点开门便有食客排队等候，是汕头人心中卤鹅第一品牌。', '/images/food/春梅里鹅肉店/1.png', '汕头市金平区中山路86号', 23.3590, 116.6780, '人均40-80元', 4.5, '["卤味","老字号","狮头鹅","汕头必吃"]', TRUE, 8900),
(2, '老潮兴粿品', 'shop', '汕头老潮兴是制作潮汕粿品的专业老店，由潮汕粿品制作技艺省级传承人郑锦辉创立。店内常年供应红桃粿、鼠壳粿、甜粿、发粿、菜头粿、芋粿等数十种传统粿品。坚持纯手工制作，从磨米浆到蒸制全程不假手机器，保留了最地道的古早风味。', '/images/food/老潮兴粿品/1.png', '汕头市金平区民族路56号', 23.3580, 116.6760, '人均10-30元', 4.4, '["粿品","老字号","非遗","手工"]', TRUE, 6200),
(4, '胡荣泉春饼', 'shop', '潮州百年老字号胡荣泉，始创于清宣统二年（1910年），是潮州最负盛名的传统饼食和小吃店。春饼是胡荣泉的招牌产品，用薄如蝉翼的面皮包裹绿豆瓣、猪肉、香菇、虾米等馅料炸制而成，外皮金黄酥脆层次分明，内馅咸香丰腴汁多味美。此外胡荣泉的腐乳饼、朥饼（潮式月饼）、酥糖等也远近驰名。', '/images/food/胡荣泉春饼/1.png', '潮州市湘桥区太平路145号', 23.6650, 116.6480, '春饼5-8元/个', 4.6, '["春饼","百年老字号","小吃","潮州"]', TRUE, 7300),
(2, '爱西干面', 'shop', '爱西干面是汕头最具代表性的传统面食之一，其历史可追溯至民国时期。以手工制作的碱水面为主角，面条筋道弹牙有嚼劲，拌上秘制葱油、酱油和猪油后香气四溢。标配一碗猪杂汤，汤头用猪骨和大地鱼干熬制奶白浓郁，内有猪肉片、猪肝、猪肚、肉饼和几颗弹牙鱼丸。面与汤搭配食用，一干一湿相得益彰。', '/images/food/爱西干面/1.png', '汕头市金平区外马路213号', 23.3550, 116.6720, '人均20-40元', 4.3, '["干面","老字号","面食","汕头"]', FALSE, 4500),
(2, '镇记牛杂', 'shop', '潮州西湖边的镇记牛杂是潮州牛杂粿条的标杆名店，始于1985年。一碗牛杂粿条用料极其慷慨，牛肚、牛筋、牛腩、牛百叶、牛心、牛舌铺满碗面，汤底以南姜、香茅等多种香料熬制，撒上炸蒜蓉和芹菜末后鲜香逼人。店家每天凌晨四点起来熬汤，六点半开门便有食客等候，一碗下肚浑身舒泰。', '/images/food/镇记牛杂/1.png', '潮州市湘桥区环城西路104号', 23.6700, 116.6420, '人均20-40元', 4.5, '["牛杂","粿条","早餐","潮州"]', TRUE, 9800),
(6, '隆江猪脚饭', 'dish', '隆江猪脚饭发源于揭阳市惠来县隆江镇，是潮汕地区家喻户晓的快餐美食。选用优质猪前蹄，经焯水、拔毛、腌制后放入由八角、桂皮、南姜、陈皮、冰糖、酱油等调制的老卤中慢炖六小时以上。炖好的猪脚皮色红亮晶莹剔透，用筷子轻轻一夹即骨肉分离，入口软糯滑润肥而不腻。配上一碗白米饭，淋上几勺卤汁，就是最地道的隆江猪脚饭。', '/images/food/隆江猪脚饭/1.png', '', NULL, NULL, NULL, 4.2, '["猪脚饭","快餐","隆江","卤味"]', FALSE, 3800),
(4, '金新肠粉', 'shop', '汕头肠粉与广式肠粉风格迥异，汕头肠粉皮较厚实Q弹，馅料更加丰富豪放。金新肠粉是汕头经营超过三十年的肠粉老店，一条牛肉肠粉里塞满了鲜牛肉、豆芽、生菜、鸡蛋和菜脯粒，浇上秘制酱汁后香气扑鼻。口感层次极为丰富——肠粉皮滑嫩、牛肉鲜甜、蔬菜爽脆、菜脯咸香，一条下肚已半饱。', '/images/food/金新肠粉/1.png', '汕头市金平区金新南路28号', 23.3630, 116.6920, '人均10-25元', 4.3, '["肠粉","早餐","小吃","汕头"]', TRUE, 7100),
(5, '鸭母捻', 'dish', '鸭母捻是潮汕独有的传统甜汤，因其形状椭圆如鸭蛋在糖水中翻滚如母鸭游水而得名。以糯米粉为皮，内包芝麻馅、花生馅或芋泥馅，搓成椭圆形的汤圆，放入由白果、莲子、红枣、银耳、薏米、鹌鹑蛋等熬制的甜汤中同煮。汤色晶莹、丸子软糯、配料丰富甜蜜，是潮汕人从小到大最温暖的冬日记忆。', '/images/food/鸭母捻/1.png', '', NULL, NULL, NULL, 4.4, '["甜汤","传统","冬季","潮汕特色"]', FALSE, 2900),
(4, '糖葱薄饼', 'dish', '糖葱薄饼是潮汕地区最具特色的传统糖点之一，被《舌尖上的中国》报道后火遍全国。"糖葱"并非真正含有葱，而是将麦芽糖经过反复拉抻折叠成千层酥脆的糖条，截面气孔密布形似葱管，故名糖葱。取一张薄如蝉翼的面皮，放上一块糖葱，撒上芝麻、花生碎和椰丝，再放上一小撮香菜（芫荽），卷起即食。入口酥脆化渣、甜而不腻、香气馥郁。', '/images/food/糖葱薄饼/1.png', '', NULL, NULL, NULL, 4.0, '["糖葱","传统小吃","舌尖上的中国","甜食"]', TRUE, 5500),
(2, '老二炒粿', 'shop', '老二炒粿是汕头老市区著名小吃店，主打潮汕特色炒糕粿。糕粿是用米粉蒸制的方形粿块，切成小块后在大火铁板上煎至两面金黄微焦，加入鸡蛋、豆芽、韭菜同炒。最独特的是上桌前撒上一层糖粉——咸甜交织的复合口味令人欲罢不能。口感外焦里嫩，镬气十足，是潮汕人从小吃到大的街坊美食。', '/images/food/老二炒粿/1.png', '汕头市金平区民族路44号', 23.3580, 116.6750, '人均12-25元', 4.1, '["炒粿","小吃","老市区","潮汕特色"]', FALSE, 3100),
(3, '适口砂锅粥', 'shop', '潮汕砂锅粥是潮汕人夜宵文化的重要组成部分，与广式粥的绵密不同，潮汕粥米粒分明有嚼劲。适口砂锅粥是汕头著名砂锅粥专门店，螃蟹鲜虾粥是招牌，现点现杀活蟹活虾与生米同时入砂锅大火滚煮，米粒吸饱海鲜精华，上桌前撒上胡椒粉和芹菜粒，粥鲜料足暖胃暖心。', '/images/food/适口砂锅粥/1.png', '汕头市龙湖区珠江路12号', 23.3700, 116.7300, '人均50-120元', 4.5, '["砂锅粥","夜宵","海鲜","暖胃"]', TRUE, 6400),
(3, '新梅园安平酒家', 'shop', '新梅园安平酒家是汕头老牌潮菜酒楼，以正宗传统潮州菜著称。招牌菜包括炭烧响螺、梅汁蒸鳗鱼、明炉乌鱼、芋泥白果等经典潮菜。炭烧响螺由老师傅在桌边现场操作，螺肉切片后用高汤和花雕酒灼熟，口感脆嫩鲜甜回味悠长。环境典雅大气，适合家庭聚餐、商务宴请和婚庆寿宴。', '/images/food/新梅园安平酒家/1.png', '汕头市金平区安平路55号', 23.3600, 116.6750, '人均180-350元', 4.3, '["潮菜","宴请","海鲜","老字号"]', FALSE, 4200);
INSERT INTO heritages (name, category, type, description, image_url, video_url, inheritor, region, view_count) VALUES
('潮州音乐', '国家级', '传统音乐', '潮州音乐是潮汕地区传统音乐的统称，包括弦诗乐、笛套古乐、潮州锣鼓乐等。以二弦为领奏乐器，音色古朴典雅，旋律优美流畅，是中国传统音乐中的活化石。', '/images/events/Heritage/潮州音乐 (1).jpg', '', '黄义孝', '汕头', 9200),
('英歌舞', '国家级', '传统舞蹈', '英歌舞是潮汕地区独有的传统舞蹈，表演者画着脸谱，手持英歌槌，模仿梁山好汉攻打大名府的故事。动作刚劲有力，气势磅礴，被誉为"中华战舞"。春节期间各乡里巡游时最为壮观。', '/images/events/Heritage/英歌舞1.jpg', '', '陈来发', '潮阳', 15800),
('潮剧', '国家级', '传统戏剧', '潮剧是用潮汕方言演唱的古老地方剧种，已有500多年历史。唱腔优美，表演细腻，有"南国奇葩"之誉。著名剧目有《荔镜记》《苏六娘》等。', '/images/events/Heritage/潮剧 (1).jpg', '', '姚璇秋', '汕头', 11200),
('潮汕工夫茶', '国家级', '传统技艺', '潮汕工夫茶是中国茶道的"活化石"，讲究"和、敬、精、乐"四字精神。茶叶以凤凰单丛为代表，茶具讲究"四宝"：玉书煨、潮汕炉、孟臣罐、若琛杯。', '/images/events/Heritage/潮汕工夫茶 (1).jpg', '', '陈香白', '潮州', 8900),
('嵌瓷', '国家级', '传统美术', '潮汕嵌瓷是用彩色瓷片在建筑上进行装饰的传统技艺，多用于庙宇、祠堂的屋顶和墙壁。色彩艳丽，经久不褪，被称为"屋顶上的艺术"。', '/images/events/Heritage/嵌瓷 (1).jpg', '', '卢芝高', '潮州', 4300),
('潮汕木雕', '国家级', '传统美术', '潮汕木雕以多层镂空、金漆贴饰为特色，题材多为戏曲故事、花鸟鱼虫。用于建筑装饰、家具、神龛等，工艺精湛。', '/images/events/Heritage/潮汕木雕 (1).jpg', '', '陈舜羌', '潮州', 6100),
('铁枝木偶', '省级', '传统戏剧', '潮汕铁枝木偶又称"纸影戏"，表演者通过铁枝操控木偶，配以潮剧唱腔，在小型舞台上演出。是潮汕农村节庆常见表演。', '/images/events/Heritage/铁枝木偶 (1).jpg', '', '陈培森', '揭阳', 2100),
('潮汕剪纸', '省级', '传统美术', '潮汕剪纸以精细秀丽著称，题材多为吉祥图案、花鸟鱼虫。常用于年节装饰、祭祀礼品等。', '/images/events/Heritage/潮汕剪纸 (1).jpg', '', '许舜英', '潮州', 1800),
('潮州大锣鼓', '省级', '传统音乐', '潮州大锣鼓是潮汕地区最具代表性的民间打击乐合奏，以大鼓为中心，配以深波、苏锣、大小钹等。气势磅礴，常用于游神赛会。', '/images/events/Heritage/潮州大锣鼓 (1).jpg', '', '黄壮茂', '潮州', 3200),
('普宁英歌', '国家级', '传统舞蹈', '普宁英歌与潮阳英歌同源异流，动作更加粗犷有力，节奏感更强。是普宁地区春节期间最受欢迎的民俗表演。', '/images/events/Heritage/普宁英歌 (1).jpg', '', '陈汉明', '普宁', 5400),
('潮州抽纱', '国家级', '传统美术', '潮州抽纱是潮汕地区最具代表性的手工刺绣技艺之一。以白色或浅色棉布为底，通过抽、绣、钩、织等数十种精细针法，创造出虚实相间、玲珑剔透的立体图案。产品包括台布、床罩、窗帘、手帕、服装等，远销欧美和东南亚，是潮汕传统手工艺出口创汇的主力品种。2014年被列入国家级非物质文化遗产名录。', '/images/events/Heritage/潮州抽纱 (1).png', '', '林智成', '潮州', 3700),
('枫溪瓷烧制技艺', '国家级', '传统技艺', '潮州枫溪是中国瓷都的核心产区，枫溪瓷烧制技艺历史悠久可溯至唐宋。枫溪瓷以白瓷为主，胎质细腻洁白温润如玉，器型多样涵盖花瓶、茶具、餐具和陈设艺术瓷等。最具特色的是通花瓷和瓷花，瓷花薄如蝉翼栩栩如生，需要匠人数十年功力才能掌握。2011年列入国家级非遗名录。', '/images/events/Heritage/枫溪瓷烧制技艺 (1).png', '', '王龙才', '潮州枫溪', 5600),
('潮州花灯', '国家级', '传统美术', '潮州花灯是南方最具代表性的传统灯彩艺术之一，与自贡灯彩并称中国两大灯彩体系。以竹篾铁丝为骨架，糊以绢纱薄纸，施以精美彩绘，题材涵盖历史人物、戏曲故事、花鸟瑞兽和亭台楼阁。大型走马灯利用热气流驱动内层转动光影流转美轮美奂。每年元宵潮州古城万灯齐亮，牌坊街至广济楼沿途灯火璀璨如星河坠落，是中国四大灯会之一。2008年列入国家级非遗名录。', '/images/events/Heritage/潮州花灯 (1).png', '', '林汉彬', '潮州', 4900),
('大吴泥塑', '国家级', '传统美术', '潮州市潮安区浮洋镇大吴村以泥塑闻名，大吴泥塑与天津泥人张、无锡惠山泥人并称中国三大泥塑。大吴泥塑以精细传神著称，取材广泛涵盖戏曲人物、民间故事、市井生活、佛像神像等。制作需经选土、练泥、塑形、阴干、烧坯、彩绘等十几道工序，人物表情生动眉眼传神衣纹流畅，方寸之间尽显功力。2008年列入国家级非遗名录。', '/images/events/Heritage/大吴泥塑 (1).png', '', '吴光让', '潮州潮安', 3100),
('潮州歌册', '国家级', '民间文学', '潮州歌册是潮汕女性群体中世代口耳相传的长篇叙事说唱文学，用潮汕方言吟唱，音韵优美如歌似吟。内容多取材于历史演义、才子佳人、民间传说，如《梁山伯与祝英台》《陈三五娘》《薛仁贵征东》等，篇幅动辄数千行甚至上万行。妇女们农闲时三五成群围坐绣房或庭院，一人主唱众人应和，在歌声中传承历史故事和道德教化。2008年列入国家级非遗名录。', '/images/events/Heritage/潮州歌册 (1).png', '', '林瑞华', '潮州', 1800),
('潮州鲤鱼舞', '省级', '传统舞蹈', '潮州鲤鱼舞是潮汕地区春节期间最具喜庆色彩的民间舞蹈之一，流传于潮州、汕头、揭阳等地村镇。表演者身披彩绘鲤鱼道具，在锣鼓伴奏下模仿鲤鱼摆尾、跳跃、嬉水、跃龙门等动作，舞步轻快灵动姿态优美。鲤鱼在中国传统文化中寓意年年有余和鱼跃龙门，因此鲤鱼舞多在春节元宵期间与舞龙舞狮同台演出。2011年列入广东省非物质文化遗产名录。', '/images/events/Heritage/潮州鲤鱼舞 (1).png', '', '陈镇坤', '潮州', 1500),
('揭阳青狮', '国家级', '传统舞蹈', '揭阳青狮是潮汕地区最具威猛气势的传统狮舞，与普通舞狮不同，青狮面目更加狰狞威武、动作更加刚猛有力。青狮表演融合了武术、杂技和舞蹈元素，有登高、踩青、过桥等高难度动作，需要表演者具备深厚的武术功底。每逢重大节庆和地方盛典，青狮队浩浩荡荡出巡，锣鼓喧天中青狮腾挪跳跃威震四方。2011年列入国家级非遗名录。', '/images/events/Heritage/揭阳青狮 (1).png', '', '孙淑强', '揭阳榕城', 2800),
('潮州麦秆剪贴画', '省级', '传统美术', '潮州麦秆剪贴画是利用小麦秆为原料，经过浸泡、剖刮、烫色、剪刻、拼贴等多道工序制成画面的独特工艺美术品。匠人将麦秆剖成薄如蝉翼的片材，利用麦秆天然的金属光泽和纹理，通过巧妙组合形成山水、花鸟、人物等画面。作品金光闪闪、层次分明、立体感强，远观如金丝镶嵌富丽堂皇，近看方知是纤细麦秆所成。2012年列入广东省非遗名录。', '/images/events/Heritage/潮州麦秆剪贴画 (1).png', '', '方志伟', '潮州', 1200),
('潮州金银錾刻技艺', '省级', '传统技艺', '潮州金银錾刻技艺是用特制錾刀在金银器表面凿刻出精美图案和文字的传统手工技艺。潮州金银錾刻以精细繁复著称，一件大型银器往往需要錾凿数十万刀历时数月方能完成。产品涵盖金银首饰、餐具、摆件和宗教法器，其中潮州银花丝和錾刻龙凤手镯最为著名。2012年列入广东省非遗名录。', '/images/events/Heritage/潮州金银錾刻技艺 (1).png', '', '郑桂泳', '潮州', 900),
('汕头抽纱', '省级', '传统美术', '汕头抽纱与潮州抽纱同源，但在风格和技法上各具特色。汕头抽纱更注重图案的对称性和几何美感，纹样多采用花卉藤蔓和几何图形，风格典雅大方。汕头抽纱在二十世纪初通过汕头港大量出口至欧洲和南洋，是汕头开埠文化的重要象征。2015年列入广东省非遗名录。', '/images/events/Heritage/汕头抽纱 (1).png', '', '陈丽华', '汕头', 800),
('揭阳玉雕', '省级', '传统技艺', '揭阳玉雕是广东省非物质文化遗产项目，依托揭阳阳美村这个中国最大的中高档翡翠加工集散地发展而来。阳美玉雕以翡翠雕刻为主，工匠善于根据玉料天然的色泽纹理因材施艺，巧用俏色将玉料瑕疵化为点睛之笔。产品涵盖手镯、挂件、摆件等，工艺水平全国领先。揭阳阳美与云南腾冲、广东平洲、四会并称中国四大玉器市场。', '/images/events/Heritage/揭阳玉雕 (1).png', '', '夏禄林', '揭阳', 1300),
('潮安凤凰山畲族招兵节', '省级', '民俗', '凤凰山畲族招兵节是潮州市潮安区凤凰山畲族同胞最隆重的传统祭祀节日，每三年在农历冬至前后举办一次，历时三天三夜。活动内容包括请神、祭祖、招兵、上刀梯、过火海、竹竿舞等，场面神秘壮观，展现了畲族独特的民族文化和勇敢坚韧的民族性格。凤凰山是畲族的发祥地，被全国畲族同胞视为祖山圣地。', '/images/events/Heritage/潮安凤凰山畲族招兵节 (1).png', '', '蓝金泉', '潮州凤凰山', 1600);
INSERT INTO folk_events (name, description, event_date, lunar_date, region, image_url, event_type) VALUES
('营老爷巡游', '营老爷巡游是潮汕地区规模最盛大、参与人数最多、最具代表性的传统民俗活动。"营"在潮汕话中是"游"的意思，"老爷"则是对地方保护神的尊称。每年农历正月初至二月间，潮汕各地乡村城镇都会举办营老爷活动，其中以汕头澄海、潮阳、潮州庵埠等地最为隆重。活动通常由村中长老和理事会组织，提前数月筹备，包括筹集香油钱、修缮神轿、排练锣鼓队和标旗队等。正日当天，由村中青壮年将三山国王、妈祖、关帝等地方守护神像从庙宇中恭敬请出，安置于精雕细琢的神轿之上，由八人或十六人抬行。巡游队伍绵延数百米乃至数里，依次为开道锣鼓、回避肃静牌、彩旗方阵、标旗队、潮州大锣鼓班、英歌舞队、舞狮舞龙队、以及压阵的神轿。沿途家家户户在门前摆香案、备供品，焚香点烛，燃放鞭炮，迎接"老爷"经过。巡游路线通常覆盖村中主要街巷和田头地尾，寓意神明巡视全境，驱邪纳福，保佑风调雨顺、五谷丰登、合境平安。巡游过程中，还会有"走老爷"的环节，即抬轿者快速奔跑甚至将神轿高高抛起接住，场面惊险刺激，围观群众喝彩声震天。营老爷不仅是一场宗教仪式，更是凝聚乡情、联络宗族的重要场合，许多海外华侨都会特意选在这个时候回乡参加，体现了潮汕人浓厚的地域认同和宗族观念。活动结束后还有规模盛大的"食桌"宴席，全村老少和远方宾客围坐共享，其乐融融。营老爷巡游已于2014年被列入国家级非物质文化遗产代表性项目名录。', '2026-02-17', '正月初四', '汕头澄海', '', 'festival'),
('元宵灯会', '元宵灯会是潮汕地区最具诗情画意的传统节日庆典，每年农历正月十五举办，标志着春节庆祝活动的压轴高潮。潮州古城的元宵灯会尤为壮观，被誉为"岭海名邦第一灯"。自宋代起潮州就有上元张灯的习俗，明清时期达到鼎盛。每逢元宵夜，潮州牌坊街至广济门城楼沿线万灯齐亮，百戏杂陈。灯会以传统花灯为主角，潮州花灯是中国四大名灯之一，制作工艺极为考究，以竹篾为骨架，糊以绢纱，施以彩绘，题材涵盖戏曲人物、花鸟鱼虫、民间故事等。大型走马灯利用热气流推动内层转动，光影流转间演绎《陈三五娘》《苏六娘》等潮剧经典桥段。此外还有纱灯、宫灯、活灯（机械动画灯）、吊灯等几十个品种，琳琅满目。潮州府城的"灯楼"习俗尤为独特——各街坊竞相搭建高达数丈的灯棚，层叠悬挂数千盏花灯，灯火辉煌彻夜不熄，坊间互相攀比争奇斗艳。游灯是元宵另一项重要内容，家家户户提灯笼出行，儿童手持鲤鱼灯、兔灯欢快奔跑，青年男女以灯会友，暗生情愫。猜灯谜更是潮汕元宵一绝，潮汕灯谜文化底蕴深厚，谜面常以潮汕方言出题，妙趣横生。在潮州古城的叩齿庵、开元寺、西湖公园等处都设有大型灯谜台，文人雅士和市井百姓同台竞猜，射中者击鼓三声领取彩头，气氛热烈。汕头小公园、澄海陈慈黉故居、揭阳学宫等地也会举办各具特色的元宵灯会。品元宵汤圆（潮汕称"鸭母捻"）也是节日传统，一家人围坐吃甜汤，寓意团圆美满、生活甜蜜。潮州元宵灯会现已成为广东省非物质文化遗产项目，每年吸引数十万游客前来赏灯。', '2026-03-04', '正月十五', '潮州古城', '', 'festival'),
('端午节赛龙舟', '潮汕地区的端午节赛龙舟是一项集竞技、祭祀、民俗于一体的大型水域活动，有着数百年历史。潮汕地处韩江、榕江、练江三江出海交汇处，水网密布，为龙舟活动提供了得天独厚的自然条件。主要分布区域包括汕头南澳岛、澄海东里河、潮州韩江段、饶平黄冈河、揭阳榕江等地。每年农历五月初五，数十支甚至上百支龙舟队汇聚于各大水域，展开激烈角逐。潮汕龙舟有其独特形制，船身细长呈流线型，龙头高昂雕刻精美，龙尾翘起气势非凡，一般可容二十至四十名桡手。开赛前先要举行庄重的"祭龙头"仪式：由村中有名望的长者为主祭，在三牲果品前焚香祷告，为龙头点睛开光，祈求水神保佑赛事平安、风调雨顺。点睛后龙头被郑重安放于舟首，船员齐声呐喊，鞭炮齐鸣，龙舟正式下水。比赛时分多条赛道，以抢标或计时决胜。桡手们身着统一服装，跟随船头鼓手敲击的急促鼓点，齐声吆喝奋力挥桨，船桨入水划破碧波，水花四溅如银珠飞迸。岸边人山人海，锣鼓声、呐喊声、鞭炮声交织在一起震耳欲聋，观众热情高涨为自己村落的队伍助威。南澳岛的海上龙舟赛因受海潮影响更具挑战性，桡手需要掌握潮汐规律调整划行节奏。澄海的龙舟与游神结合，龙舟赛后还会将龙舟抬上岸巡游乡里。除了赛龙舟本身，端午节潮汕各户还会在家门口悬挂艾草和菖蒲以驱邪避瘟，用午时水洗浴以求健康平安。吃粽子（潮汕称"粽球"）必不可少，潮汕粽球独具特色，以咸甜双拼最为经典，一半咸香配以五花肉、香菇、咸蛋黄、虾米，一半甜糯配以豆沙、白果、莲子，一粽两味相映成趣。饶平、澄海等地还有包栀粽的独特传统，用栀子和糯米制成的碱水粽蘸白糖食之清香爽口。端午节赛龙舟已被列入广东省非物质文化遗产保护名录。', '2026-06-19', '五月初五', '汕头南澳', '', 'festival'),
('出花园', '"出花园"是潮汕地区独有的传统成人礼仪式，也是中国最具特色的民间成年礼之一，被列入国家级非物质文化遗产代表性项目名录。这一习俗广泛流传于汕头、潮州、揭阳、汕尾等潮汕核心区域，以及海内外所有潮汕人聚居地。按照潮汕传统，孩子自出生起就被视为生活在"花园"中，由"公婆神"（也称"床脚婆"或"花公花妈"）庇佑守护，直到十五岁才算"走出花园"正式步入成人世界。仪式固定在孩子虚岁十五岁那年的农历七月初七（乞巧节）举行，取牛郎织女鹊桥相会的吉祥寓意。仪式前一天，家人便开始忙碌准备：用十二种鲜花（如石榴花、仙草、芙蓉、红花等）浸泡成"花水"，寓意十二个月月月平安。七夕当天清晨，行成人礼的孩子用花水沐浴净身，象征洗涤童年稚气。沐浴后换上一身全新的红肚兜和新衣新鞋，肚兜内放入十二个熟红鸡蛋，代表十二个月的圆满。孩子的母亲或族中长辈女性在"公婆神"神位前摆上三牲、红桃粿、发粿、甜汤圆等丰盛供品，焚香祷告，感谢神明十五年来的庇佑之恩。随后设一桌宴席，菜肴必须凑足十二道或十二的倍数，其中必有全鸡（寓意独立）、全鱼（寓意有余）、猪肝炒葱（寓意聪明）等寓意吉祥的菜品。主角须坐在用竹篾编织的"胶掠"（圆形大簸箕）中央，头顶撑开一把新红伞，脚踩"寿"字红纸，由家中长辈为其戴上银锁项链和手镯，口念祝福语。最有仪式感的是"咬鸡头"环节——孩子要咬一口白切鸡的鸡头，象征从此以后能独立自主、出人头地。仪式结束后宴请亲友，大家向"出花园"的孩子赠送红包和祝福。这一天孩子不能出门、不能骂人、不能说不吉利的话，象征以最纯净的状态跨入成年。出花园承载了潮汕人对后辈成长的深切关爱与殷切期盼，是一份穿越数百年的人间真情。', '2026-08-19', '七月初七', '潮汕各地', '', 'custom'),
('中秋烧塔', '中秋烧塔是潮汕地区最炽烈、最震撼人心的中秋民俗活动，以揭阳普宁、揭西以及潮州凤凰山区一带最为盛行，现已被列入广东省非物质文化遗产保护名录。烧塔的历史渊源可追溯至元朝末年——相传当时潮汕先民以中秋夜烧塔为信号联络各路义军，最终推翻了压迫者的统治，此后中秋烧塔便成为纪念先人反抗精神和祈求光明的传统习俗延续至今。活动通常在中秋节前一周开始筹备，由村中青壮年负责收集砖块、瓦片、木柴等材料。砌塔是一项技术活：先在村中广场或晒谷场上选定一块平坦空地，用红砖或石头围成圆形底座，直径约一米五至两米左右，留一个添柴的"火门"。然后自下而上用碎瓦片逐层叠砌塔身，瓦片之间留出纵横交错的空隙供火焰窜出，塔身越往上越收缩，最终形成尖顶，高约三至五米，远观如一座古朴的砖瓦宝塔。有些村庄还会在塔身外表用石灰水写上"风调雨顺""国泰民安"等吉祥大字。中秋节当晚，全村老少齐聚塔前。待明月东升，由村中有威望的长者或当年添丁的家庭代表手持火炬，从火门点燃塔内堆积的木柴和稻草。火借风势越烧越旺，火焰从瓦片千千万万缝隙中喷薄而出，整座砖塔化为一柱通体透红的"火塔"，火光冲天映红半边天际，场面极为壮观。围观村民围着烧塔欢呼雀跃，锣鼓喧天，鞭炮齐鸣。有些地方还会往塔身上撒盐，盐粒遇火发出噼噼啪啪的爆裂声和耀眼白光，寓意驱邪避灾。火烧得越旺、越高，就代表来年的日子越红火、运势越旺。烧塔过程中还有赏月、吃月饼、品工夫茶的环节，一家人团坐塔旁，一边赏月品茶，一边看火焰舞蹈，其乐融融。烧塔结束后，孩子们在余烬中烤番薯、芋头，香气四溢。灰烬在次日清晨由村民收集撒入田间，据说可做肥料使来年庄稼丰收。', '2026-09-25', '八月十五', '揭阳普宁', '', 'custom'),
('冬至祭祖', '潮汕地区素有"冬大过年"的古老谚语，冬至在这个地区的隆重程度甚至超过了春节，是全年最重要的家族祭祀节日。这一传统广泛分布于汕头、潮州、揭阳、汕尾四市及其辖下所有区县村镇。冬至祭祖习俗源远流长，可追溯至周代，潮汕先民南迁时将这一中原古礼带入岭南并完整保留至今。潮汕人认为冬至是阴阳交替、阳气始生的关键时刻，"冬至一阳生"，是祭拜祖先、感念祖德的最佳时机。节前数日，家家户户便开始大扫除，擦洗祖先牌位和神龛，准备丰盛的供品。供品极为讲究，须包含三牲（鸡、鸭、猪肉或猪头五牲）、红桃粿、发粿、甜粿、甜汤圆、水果、茶酒等。其中"冬至丸"（糯米汤圆）是绝对主角，潮汕冬至丸有红白两色，红色用食用色素染就，红白相间盛于碗中煞是好看。制作时全家老少围坐一起搓丸子，边搓边聊家常，气氛温馨融洽。冬至当天清晨，家中男丁沐浴更衣后在祠堂或家中神龛前摆上供桌，由辈分最高的长者主祭。主祭者带领全族子孙焚香、献供、敬酒、行三跪九叩大礼，口中念诵祭文追思祖先功德，祈求先灵保佑后辈子孙身体健康、学业有成、事业顺利、添丁发财。祭毕焚烧纸钱和纸扎祭品，鸣放鞭炮。随后便是盛大的家族聚餐——"食冬节桌"，潮汕人讲究"冬至一餐补一年"，宴席上必有羊肉炉、炖鸡汤等温补佳肴。吃完冬至丸就算长了一岁，所以潮汕有俗语"吃了冬节圆，人人大一岁"。潮汕各地冬至习俗微有差异：汕头澄海等地有"谢神"习俗，即在冬至这天酬谢土地神一年的庇佑；潮州部分地区至今保留"祭祖分胙"古礼，将祭肉按户均分；揭阳惠来沿海则有冬至吃"茧"（一种用米粉皮包的菜粿）的独特食俗。冬至祭祖不仅是对祖先的缅怀，更是维系潮汕宗族纽带、传承家风家训的重要方式，承载着潮汕人对家族血脉的深挚情感和慎终追远的传统美德。', '2026-12-22', '十一月十三', '潮汕各地', '', 'festival'),
('游神赛会', '游神赛会是潮汕地区春节期间规模最大、内容最丰富的民间文化盛会，集神明祭祀、艺术表演、文化展示、体育竞技于一体，已经延续了数百年。主要分布在潮州潮安、饶平，汕头潮阳、澄海，揭阳普宁、揭东等地，尤以潮安区庵埠镇、彩塘镇举办的规模最为宏大。活动通常从正月初延续至二月中旬，各村轮流举办形成连续的节庆周期。游神赛会以"赛会"为核心，"游"指神明巡境，"赛"则兼有比赛和展示双重含义——各村的标旗队、锣鼓班、英歌队等拿出看家本领互相较劲比拼。筹备工作往往早在几个月前开始：标旗队少女精心刺绣制作锦旗，锦旗上绣有"国泰民安""五谷丰登"等吉祥词句，金银丝线在日光下熠熠生辉；潮州大锣鼓班加紧排练，领奏的二弦和司鼓者须技艺精湛才能掌控全局节奏；英歌队是游神赛会的灵魂节目，表演者画着梁山好汉脸谱，手持英歌槌，在急促鼓点中跳出刚劲有力的舞步，队列变化多达数十种，被誉为"中华战舞"。活动正日，整个村镇万人空巷。游神队伍以三声铳炮为号开始行进，打头的是"马头锣"开路，接着是回避牌和肃静牌彰显庄严，然后是数百面各色彩旗组成的旗阵迎风招展。紧随其后的是标旗方阵、花篮队、锣鼓队、弦乐队、英歌队、舞龙队、舞狮队、布马舞和挑花篮等几十个方阵，队伍绵延数里之遥。神轿居中压阵，由多名壮汉抬行，沿途香火缭绕、炮声震天。各村的"赛会"竞技也相当激烈，往往以庙前广场为擂台，英歌比武、锣鼓对垒、标旗评比，胜者获赠"锦标"旗帜和丰厚奖金。除了巡游和竞技，活动现场还有潮剧演出、木偶戏、灯谜竞猜、舞狮采青等文化娱乐活动，各类潮汕小吃摊档沿街摆开，牛肉丸、蚝烙、粿条汤、春饼等香气四溢，热闹非凡。游神赛会犹如一场流动的潮汕文化博物馆，浓缩了潮汕民俗的精髓，2011年"潮州游神赛会"已入选广东省非物质文化遗产代表性项目。', '2026-03-10', '二月初二', '潮州潮安', '', 'event'),
('潮汕侨批文化展', '侨批是潮汕地区独有的珍贵历史文化遗产，特指清末至二十世纪八十年代间，海外潮汕华侨通过民间渠道寄回家乡的"银信合一"特殊邮传载体——"批"即书信，"银"即汇款。侨批文化展主要依托汕头侨批文物馆举办，该馆位于汕头市金平区小公园开埠区，是全国首家以侨批为主题的专题博物馆，馆藏侨批原件超过三万件，是世界上规模最大的侨批收藏机构。侨批起源于清代汕头开埠之后，大量潮汕人"过番"（潮汕话指下南洋）谋生，足迹遍及泰国、新加坡、马来西亚、印尼、越南、柬埔寨等东南亚各国。这些海外游子辛苦劳作省吃俭用，将积攒的血汗钱连同亲笔家书通过"水客"或"批局"、"批信局"寄回家乡赡养家人。"批"字在潮汕话中兼有信件和汇款凭证双重含义，一封侨批上既有批信文字又有汇款数额，构成了独一无二的金融与情感双重载体。一封侨批往往承载着一个家族的故事——开头必是询问长辈安康、妻儿平安的牵挂话语，然后写明随信寄回银钱数额及用途分配，最后用"切切此嘱"等殷切词句收尾。在动荡的年代里，侨批为潮汕数百万家庭提供了重要的经济支撑，大量侨汇用于建房立业、婚丧嫁娶、捐资办学、修桥铺路等公益事业。侨批文化展以"纸短情长——侨批里的家国记忆"为主题，展出从清末至二十世纪八十年代跨越百余年的代表性侨批原件，辅以水客竹篮、批局招牌、批信印章等实物，通过场景复原、多媒体互动等现代化展陈手段再现当年侨批业的运作流程。展览分四个篇章："下南洋·闯天涯"讲述先侨飘洋过海的奋斗历程；"批一封·银二元"展示侨批业的运作体系；"字字血·句句泪"呈现侨眷两地相隔的思念之痛；"汇百川·报桑梓"回顾侨汇对家乡建设的巨大贡献。侨批不仅是一部海外华侨的奋斗史，更是一部潮汕经济社会发展的缩影，于2013年入选联合国教科文组织《世界记忆名录》，属于全人类共同的文化遗产。', '2026-04-05', '二月十九', '汕头侨批文物馆', '', 'event'),
('盐灶拖神', '盐灶拖神是汕头澄海盐灶乡独有的极其狂野震撼的民俗活动，在全国范围内极为罕见。每年农历正月廿一至廿二举行，其中最震撼的是"拖老爷"环节——村中青壮年争相冲上神轿将被称为"盐灶老爷"的神像拼命往下拖拽，泥水中翻滚拉锯混战数小时，场面混乱至极却寓意深刻：潮汕人认为老爷越是被折腾得狼狈不堪来年就越风调雨顺。这一看似悖逆的习俗实际上反映了潮汕人与神明之间亲密互动的关系——神明不是高高在上不可触碰的偶像，而是与村民休戚与共的"自家人"，可以开玩笑可以拉扯。这种独特的民间信仰形式吸引了大量摄影爱好者和民俗研究者前来观摩拍摄。', '2026-03-08', '正月廿一', '汕头澄海盐灶', '', 'festival'),
('澄海赛大猪', '澄海赛大猪是汕头澄海区冠山乡、上华镇等地元宵期间举办的奇特民俗活动。所谓的"赛"并非让猪奔跑比赛，而是各家各户将精心饲养了一整年的大肥猪宰杀后褪毛洗净，披红挂彩摆放在祠堂或庙前广场上比赛谁家的猪最大最肥。参赛猪只动辄三四百斤甚至超过五百斤，猪身上还贴着红纸写着户主姓名和吉祥祝语。评选出的"猪王"主人被视为勤劳致富的典范，在全村面前风光无限。赛大猪活动既展示了潮汕农民的精湛养殖技艺，也蕴含着五谷丰登六畜兴旺的美好祈愿。比赛结束后猪肉分赠亲友邻里共享，体现潮汕人浓厚的乡邻情谊。', '2026-03-05', '正月十六', '汕头澄海冠山', '', 'custom'),
('潮州青龙庙会', '潮州青龙庙会是潮州府城规模最大、历史最悠久的传统庙会，每年正月廿三至廿五举办。青龙古庙（安济王庙）位于潮州古城南门外韩江之滨，始建于明代，供奉安济圣王。庙会期间举行规模盛大的安济圣王出巡活动，巡游队伍绵延数里，包括回避牌、彩旗阵、标旗队、锣鼓班、舞龙舞狮、英歌舞等数十个方阵，加上随行的香客信众，参与者常达数万人之多。神轿所过之处万人空巷夹道焚香跪拜，场面庄严盛大令人动容。庙会期间还有潮剧连演三天三夜酬神助兴，各地商贩云集摆摊，各类潮汕小吃和手工艺品琳琅满目，是一幅流动的潮汕民俗风情画卷。', '2026-03-11', '正月廿三', '潮州古城', '', 'festival'),
('揭阳行头桥', '揭阳"行头桥"是揭阳榕城独特的元宵民俗，在正月十一至十五期间举行。所谓"头桥"特指揭阳榕城区石狮桥（原名北门桥），古榕城有"正月行头桥"的俗谚。民众在元宵期间结伴走过石狮桥，并在桥上摸石狮祈福——摸狮头祈求聪明伶俐学业有成，摸狮肚祈求财源广进生意兴隆，摸狮尾祈求做事有头有尾善始善终。行桥时口中还要念吉祥俗语："行桥头，摸狮头，读书聪明好彩头"、"行桥肚，摸狮肚，赚大钱娶雅嬷（漂亮老婆）"。古朴的石桥在节日期间张灯结彩人流如织，承载着一代代揭阳人最朴素的祈福和愿望。', '2026-03-01', '正月十一', '揭阳榕城', '', 'custom'),
('盂兰盆会（施孤）', '潮汕地区的盂兰盆会俗称"施孤"，是中国保存最完整传承最地道的中元节民间祭祀活动之一，集中在每年农历七月。潮汕"施孤"融合了佛教盂兰盆会、道教中元地官赦罪和民间祖先崇拜三重文化内涵。村镇在空旷场地搭建"孤棚"（施孤台），上置米饭、面条、水果、糕点和纸钱等大量供品，由僧人道士诵经超度孤魂野鬼。最引人注目的是"抢孤"环节——法事结束后信众蜂拥冲上孤棚抢取供品带回家给小孩吃，据说吃了"孤棚"上的供品能保佑孩子平安健康成长。此外还有放水灯、烧法船等仪式，入夜后韩江水面漂满莲花水灯烛光摇曳，既是超度亡魂也是人间孝道的绵长表达。', '2026-08-26', '七月十五', '潮汕各地', '', 'custom'),
('妈祖诞辰巡游', '潮汕沿海地区信仰妈祖（天后圣母）的历史悠久，汕尾、南澳、澄海、饶平等沿海城镇及岛屿均建有妈祖庙（天后宫），其中以汕尾凤山妈祖庙和南澳深澳天后宫规模最大。每逢农历三月廿三妈祖诞辰日，各地妈祖庙联合举办盛大的巡游祈福活动。妈祖金身被恭请到华丽的神轿中，由八人抬行出巡。巡游队伍浩浩荡荡绵延数里，前方为回避牌和肃静牌开路，随后是彩旗队、标旗队、舞龙舞狮、英歌队、布马舞和潮州大锣鼓班。妈祖巡游经过的主要街道和渔港码头，渔民和信众沿途摆香案跪拜恭迎，祈求海上平安、渔业丰收。南澳岛还会举行"妈祖海上巡游"——将妈祖金身请上彩船绕岛巡航，数十艘渔船挂满彩旗跟随其后，海面鞭炮齐鸣炮声震天，场面极为壮观。', '2026-05-09', '三月廿三', '汕尾凤山/南澳', '', 'festival'),
('揭西三山国王祭', '三山国王是潮汕地区的境主神，信仰起源于揭阳市揭西县河婆镇的巾山、明山、独山三座大山，是以山神崇拜为核心的地域保护神信仰，后随潮汕移民传播至台湾和东南亚各地，全球三山国王庙超过一万座。揭西三山国王祖庙（霖田祖庙）始建于隋代，距今已有一千四百多年历史，是三山国王信仰的祖庭。每年农历二月廿五日三山国王诞辰日，祖庙举办盛大祭祀大典，来自海内外的信众齐聚祖庙进香朝圣。祭典遵循古礼，包括击鼓鸣钟、行三献礼、恭读祝文等环节，庄严肃穆。祭毕还有英歌舞、青狮舞、潮剧等民俗表演助兴，以及千人长寿宴等特色活动。', '2026-04-12', '二月廿五', '揭阳揭西', '', 'festival'),
('南澳后宅元宵渔灯会', '南澳岛后宅镇元宵渔灯会在正月十五元宵夜举行，是南澳最具海岛特色的民俗活动。南澳是广东省唯一的海岛县，渔民占总人口半数以上，渔灯会承载着渔民对出海平安和渔业丰收的深切期盼。元宵夜，南澳后宅渔港千帆归航，数百艘渔船全部挂上红灯笼和各色彩灯将港湾照得亮如白昼，海面倒映万点灯火美不胜收。岸上则有标旗巡游、渔歌对唱、潮剧演出等民俗活动，渔家妇女身穿传统服饰表演织网舞和渔歌，展示渔家文化。最受瞩目的是"送渔灯"仪式——渔民将一盏盏特制的渔灯放入大海任其漂流，每一盏灯都承载着一个家庭对新年渔业丰收的美好祝愿。', '2026-03-04', '正月十五', '汕头南澳', '', 'festival'),
('潮州广济桥灯光秀', '潮州广济桥（湘子桥）是中国四大古桥之一，与赵州桥、洛阳桥、卢沟桥齐名。近年广济桥打造的"凤城之光"灯光秀成为潮州文旅新名片，虽然并非传统民俗但已融入当代潮州节庆文化体系。灯光秀以广济桥和韩山为背景，运用现代声光电技术，将千年古桥幻化为光影画卷，配合潮州音乐和潮剧元素，讲述韩愈治潮、潮人下南洋、工夫茶道等潮州历史文化故事。灯光秀在法定节假日和周末晚上演出，每场约十五分钟，吸引大量游客前来观赏，已成为潮州城市文化新地标。', '2026-04-18', '二月廿一', '潮州广济桥', '', 'event'),
('澄海薄壳美食节', '澄海薄壳美食节是由汕头市澄海区政府和盐鸿镇共同主办的以"薄壳"为主题的美食文化活动。薄壳是潮汕特有的小海鲜贝类，学名寻氏肌蛤，因其壳极薄而得名。薄壳可炒可煮可腌，最经典的是"薄壳米"——将新鲜薄壳焯水去壳取肉，潮汕人称去壳后的贝肉为"米"，是独特的饮食语言。薄壳米晶莹剔透口感鲜嫩，是潮汕人夏天最爱的餐桌美味。美食节期间不仅有薄壳米烹饪大赛、薄壳宴品尝，还有薄壳文化展览、渔民织网表演、潮汕小吃美食街等丰富活动，吸引粤港澳大湾区大量游客前来品尝这"舌尖上的潮汕鲜味"。', '2026-07-18', '六月初六', '汕头澄海盐鸿', '', 'event'),
('澄海冠山赛大猪', '澄海冠山赛大猪与前述澄海赛大猪活动一脉相承，但冠山乡的赛大猪历史最为悠久规模最为宏大，已有超过三百年历史。冠山赛大猪在每年农历正月十六至十八举行，核心环节是正月十七的"比猪"——参赛的大肥猪被精心装扮后排列在冠山书院前的广场上，披红挂绿头戴金花，场面蔚为壮观。最大的猪王动辄重达五六百斤，饲养时间超过一年，是主人家辛勤劳动和养殖技艺的集中体现。评判标准不仅看重量还要看体形匀称、毛色光亮和装扮精美程度。赛后猪肉按传统规矩分配：猪头归主人留作纪念挂在堂屋梁上象征富足，猪肉分赠亲朋好友和同宗族人共享，体现了潮汕人团结互助、有福同享的宗族文化。', '2026-03-07', '正月十八', '汕头澄海冠山', '', 'custom'),
('潮州凤凰山祭茶祖', '潮州凤凰山是凤凰单丛茶的核心原产地，种茶制茶已有九百多年历史。每年春季采茶时节（约在清明至谷雨期间），凤凰山茶农会在乌岽山顶的宋代古茶树"宋种"前举办隆重的祭茶祖仪式。这棵宋种古茶树树龄超过七百年，被凤凰山茶农尊为"茶王""茶祖"。祭祀仪式由凤凰单丛茶制作技艺传承人主持，供奉五牲果品和当年第一杯春茶，焚香祷告感谢茶祖庇佑茶园丰收，祈祷新一年风调雨顺茶香万里。祭毕还要举办斗茶赛和茶艺表演，各地茶商茶客云集品鉴新茶，是凤凰山一年中最热闹的时节。近年来祭茶祖活动已从地方性仪式发展为潮州茶文化旅游的重要节庆品牌。', '2026-04-04', '二月十七', '潮州凤凰山', '', 'custom');
