INSERT INTO chat_messages (user_id, session_id, role, content, created_at) VALUES
(2, 'sess-demo-001', 'user', '潮汕有什么好吃的？', '2026-07-06 09:00:00'),
(2, 'sess-demo-001', 'assistant', '呐，潮汕美食可多了！牛肉火锅是头牌——八合里海记、杏花吴记都是名店，脖仁、吊龙、匙仁必点。还有粿条汤、蚝烙、生腌、卤鹅、粽球……从街头小吃到老字号，三天三夜吃不完哩！你想了解哪一类呢？', '2026-07-06 09:00:05'),
(2, 'sess-demo-001', 'user', '牛肉火锅哪家最好吃？', '2026-07-06 09:01:00'),
(2, 'sess-demo-001', 'assistant', '这个问题问得好！八合里海记是汕头最知名的老字号，牛肉新鲜现切，人均80-150元，建议中午去吃肉最新鲜。杏花吴记环境更好，适合年轻人打卡，人均100-200元。福合埕则是最老牌的，始于1960年，牛肉丸特别弹牙。三家各有特色，看你的需求啦！', '2026-07-06 09:01:08'),
(3, 'sess-demo-002', 'user', '英歌舞是什么？', '2026-07-05 14:30:00'),
(3, 'sess-demo-002', 'assistant', '英歌舞是潮汕地区独有的传统舞蹈，被誉为"中华战舞"！表演者画着脸谱，手持英歌槌，模仿梁山好汉攻打大名府的故事。动作刚劲有力、气势磅礴。春节期间（正月初一至十五）在潮阳、普宁等地的乡里巡游中可以看到。是国家级非物质文化遗产哦！', '2026-07-05 14:30:10');
INSERT INTO trip_plans (user_id, title, days, crowd_type, preferences, plan_content, status, created_at) VALUES
(2, '汕头3日美食之旅', 3, 'couple', '{"food": 0.9, "heritage": 0.4, "nature": 0.3}', '{"title":"汕头3日美食之旅","summary":"以美食为主线，穿插非遗文化和海滨风光，适合情侣悠闲出游。","tips":["建议住在金平区，离各美食点近","牛肉火锅中午去吃肉最新鲜","带上健胃消食片——好吃的东西太多了！"],"days":[{"day":1,"title":"Day 1 老市区美食探路","activities":[{"time":"09:00","name":"小公园骑楼漫步","type":"scenery","description":"感受汕头开埠文化，骑楼建筑群是绝佳拍照背景","reason":"汕头标志性景点，适合作为行程第一站"},{"time":"12:00","name":"八合里海记牛肉火锅","type":"food","description":"新鲜现切牛肉，脖仁/吊龙/匙仁必点","reason":"汕头最知名的牛肉火锅，体验潮汕美食精髓"},{"time":"15:00","name":"西堤公园+海滨长廊","type":"scenery","description":"海边散步消食，看汕头内海湾风光","reason":"饭后散步好去处"}]}]}', 'generated', '2026-07-05 10:00:00'),
(5, '潮汕4日亲子文化游', 4, 'family', '{"food": 0.6, "heritage": 0.7, "nature": 0.6}', '{"title":"潮汕4日亲子文化游","summary":"带娃深入体验潮汕非遗文化和美食，寓教于乐。","tips":["带小孩注意休息时间","部分非遗工坊可预约体验"],"days":[{"day":1,"title":"Day 1 抵达汕头·美食初体验","activities":[{"time":"12:00","name":"飘香小食店","type":"food","description":"一站式品尝蚝烙、鲎粿、无米粿等多种小吃","reason":"让孩子一次性认识多种潮汕小吃"},{"time":"15:00","name":"汕头市博物馆","type":"heritage","description":"了解潮汕历史文化","reason":"室内活动适合带孩子"}]}]}', 'generated', '2026-07-04 16:00:00');
INSERT INTO community_posts (user_id, title, content, images, tags, post_type, view_count, like_count, comment_count, created_at) VALUES
(2, '汕头八合里牛肉火锅实测！', '周末专门跑了一趟汕头，第一站直奔八合里海记。中午11点半到已经开始排队了，等了大概20分钟。点了脖仁、吊龙、匙仁、胸口朥，每盘肉都贴了标签告诉你涮几秒。脖仁最惊艳，入口即化，油脂香气在嘴里炸开。三个人吃了400多，人均130左右，性价比很高！强烈推荐给第一次来汕头的朋友。', '[]', '["美食","牛肉火锅","探店","汕头"]', 'recommend', 1520, 89, 12, '2026-07-05 11:00:00'),
(4, '潮阳英歌舞太震撼了！', '今年过年回老家，专门去潮阳看了英歌舞巡游。上百人画着脸谱，手持英歌槌，伴随着锣鼓声起舞，那个气势真的用语言形容不出来。尤其前排那个领舞的大叔，六十多岁了翻跟头还那么利索！推荐大家过年期间一定要去看看，文化自信拉满！', '[]', '["英歌舞","非遗","春节","潮阳"]', 'social', 2300, 156, 28, '2026-06-28 20:00:00'),
(3, '工夫茶入门指南：从器具到冲泡', '作为一个潮汕文化研究者，分享一份工夫茶入门指南。核心四宝：玉书煨（烧水壶）、潮汕炉（小炭炉）、孟臣罐（紫砂小壶）、若琛杯（小茶杯）。关键要点：1）茶叶用凤凰单丛，2）水温要沸，3）"高冲低斟"，4）第一泡洗茶，5）趁热闻香再品。最后提醒：喝茶时主人斟茶，客人以食指和中指轻叩桌面表示感谢（叩手礼）。', '[]', '["工夫茶","茶道","入门","教程"]', 'study', 980, 67, 15, '2026-07-03 15:00:00'),
(6, '【盲盒挑战】48小时打卡汕头8家老字号', '接受挑战！48小时内打卡汕头8家老字号：✅八合里海记 ✅老妈宫粽球 ✅飘香小食店 ✅西天巷蚝烙 ✅富苑生腌 ✅广场豆花 ✅长平路夜粥 ✅老四粿条汤。最惊喜的是老四粿条汤，一碗15元料超足！最踩雷的...说实话没有踩雷的！潮汕美食YYDS！', '[]', '["盲盒挑战","48小时","美食打卡","老字号"]', 'challenge', 1800, 203, 35, '2026-07-01 09:00:00'),
(7, '潮汕剪纸体验：一小时入门传统手艺', '周末参加了非遗传承人许老师的剪纸工作坊。从折纸开始到剪出第一朵花，花了一个小时。看起来简单做起来真不容易，力道要控制得刚刚好。最后剪了一只蝴蝶，虽然不完美但很有成就感！推荐大家去潮州牌坊街的非遗工坊体验，人均50-80元。', '[]', '["剪纸","非遗体验","手工","研学"]', 'study', 620, 42, 8, '2026-07-02 14:00:00'),
(1, '潮汕三日游保姆级攻略', '刚带朋友玩了一圈回来，整理了一份适合第一次来潮汕的朋友的三日游攻略。Day1汕头老市区美食+小公园，Day2潮州古城+牌坊街+广济桥，Day3南澳岛一日游。含交通、住宿、美食推荐，记得收藏！', '[]', '["攻略","三日游","保姆级","第一次"]', 'recommend', 3100, 278, 42, '2026-06-25 10:00:00'),
(5, '带娃逛潮汕博物馆全记录', '带5岁儿子去了汕头市博物馆，本以为他会觉得无聊，结果在"潮汕民俗"展区待了快两个小时！木雕、嵌瓷、铁枝木偶这些对他来说都是新奇的玩具。特别推荐带娃家庭去二楼互动区，可以体验简单的木雕和剪纸。', '[]', '["亲子","博物馆","遛娃","研学"]', 'study', 450, 28, 5, '2026-07-04 17:00:00'),
(8, '打卡汕头小公园最美机位分享', '来汕头小公园拍照，这几个机位一定要去：1）百货大楼正面仰拍，2）邮局转角拍骑楼透视，3）中山纪念亭拍全景。最佳时间是下午4-6点，光线斜照骑楼特别有质感。', '[]', '["拍照","小公园","打卡","机位"]', 'social', 875, 56, 9, '2026-06-30 16:00:00');
